import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate, Link } from 'react-router-dom';

function RegisterPage() {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [password2, setPassword2] = useState('');
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (password !== password2) {
      setError('Пароли не совпадают');
      return;
    }

    try {
      await axios.post('http://localhost:8000/api/register/', {
        username: username,
        password: password
      });
      setSuccess('Регистрация успешна! Перенаправляем на вход...');
      setTimeout(() => {
        navigate('/login');
      }, 2000);
    } catch (err) {
      setError('Ошибка регистрации. Возможно, имя пользователя уже занято.');
    }
  };

  return (
    <div style={{ 
      display: 'flex', 
      justifyContent: 'center', 
      alignItems: 'center', 
      minHeight: '80vh'
    }}>
      <form onSubmit={handleSubmit} style={{
        backgroundColor: '#1a1a1a',
        padding: 40,
        borderRadius: 12,
        width: 400
      }}>
        <h2 style={{ color: 'white', marginBottom: 20, textAlign: 'center' }}>Регистрация</h2>
        
        {error && <p style={{ color: '#ff4444', marginBottom: 15, textAlign: 'center' }}>{error}</p>}
        {success && <p style={{ color: '#44ff44', marginBottom: 15, textAlign: 'center' }}>{success}</p>}
        
        <input
          type="text"
          placeholder="Имя пользователя"
          value={username}
          onChange={(e) => setUsername(e.target.value)}
          required
          style={{
            width: '100%',
            padding: 12,
            marginBottom: 15,
            backgroundColor: '#272727',
            border: 'none',
            borderRadius: 8,
            color: 'white'
          }}
        />
        
        <input
          type="password"
          placeholder="Пароль"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          required
          style={{
            width: '100%',
            padding: 12,
            marginBottom: 15,
            backgroundColor: '#272727',
            border: 'none',
            borderRadius: 8,
            color: 'white'
          }}
        />
        
        <input
          type="password"
          placeholder="Подтвердите пароль"
          value={password2}
          onChange={(e) => setPassword2(e.target.value)}
          required
          style={{
            width: '100%',
            padding: 12,
            marginBottom: 20,
            backgroundColor: '#272727',
            border: 'none',
            borderRadius: 8,
            color: 'white'
          }}
        />
        
        <button type="submit" style={{
          width: '100%',
          padding: 12,
          backgroundColor: '#ff0000',
          color: 'white',
          border: 'none',
          borderRadius: 8,
          fontSize: 16,
          cursor: 'pointer'
        }}>
          Зарегистрироваться
        </button>
        
        <p style={{ color: '#aaa', textAlign: 'center', marginTop: 20 }}>
          Уже есть аккаунт? <Link to="/login" style={{ color: '#ff0000' }}>Войдите</Link>
        </p>
      </form>
    </div>
  );
}

export default RegisterPage;
